def count_words(s):
    # Split the string into words and convert them to lowercase
    words = s.lower().split()

    # Create an empty dictionary to store word counts
    word_count = {}

    # Iterate over each word in the list of words
    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

    return word_count


